mapper.sql:

select temp.* from
(select
     isnull((select pe.name  from  pm_employee pe join fnd_user fu on fu.id = smqa.update_by and fu.employee_id = pe.id  ), '') as update_by_str,
     isnull((SELECT pej.dept_id FROM pm_employee_job pej JOIN pm_employee pe ON pe.work_card = smqa.work_card AND pej.employee_id = pe.id and pej.enabled_flag=1 and  pej.job_main_flag=1 and smqa.enabled_flag=1 and pe.enabled_flag=1), '') AS dept_id,



    ,se.department as department, se.administrative_office as administrative_office
    from swm_monthly_quarterly_assessment smqa , swm_employee se where smqa.enabled_flag = 1
     and se.work_flag = 1 and smqa.se_id = se.id and smqa.assessment_type = 'month'
     union all
     select isnull((select pe.name  from  pm_employee pe join fnd_user fu on fu.id = smqa.update_by and fu.employee_id = pe.id  ), '') as update_by_str,
     isnull((SELECT pej.dept_id FROM pm_employee_job pej JOIN pm_employee pe ON pe.work_card = smqa.work_card AND pej.employee_id = pe.id and pej.enabled_flag=1 and  pej.job_main_flag=1 and smqa.enabled_flag=1 and pe.enabled_flag=1), '') AS dept_id,



    ,spss.department as department, spss.administrative_office as administrative_office
    from swm_monthly_quarterly_assessment smqa join swm_post_skill_salary spss on spss.work_card = smqa.work_card
    and spss.employee_name = smqa.name and spss.income_period = smqa.assessment_month and smqa.assessment_type = 'month'
    and spss.enabled_flag = 1  and smqa.se_id = -1


) temp where 1 = 1



           and ( (1 = 0) or


             (temp.department = #{item.department, jdbcType=VARCHAR} and
            isnull(temp.administrative_office, '-1') = isnull(#{item.administrativeOffice, jdbcType=VARCHAR}, '-1')
            )

        )




            and temp.work_card !=  (select work_card from swm_employee where employee_id = #{criteria.selfPmEmpId,jdbcType=BIGINT})




            and temp.assessment_month = #{criteria.period,jdbcType=VARCHAR}




            and temp.assessment_type = #{criteria.assessmentType,jdbcType=VARCHAR}




            and temp.frozen_flag = #{criteria.frozenFlag,jdbcType=BIT}





                and temp.department = #{criteria.managerDepartment, jdbcType=VARCHAR}




                and se.administrative_office = #{criteria.managerAdministrativeOffice, jdbcType=VARCHAR}

mapper.update:

update  swm_monthly_quarterly_assessment set enabled_flag = 0,
        update_time  = #{updateTime,jdbcType=TIMESTAMP},
        update_by    = #{updateBy,jdbcType=BIGINT}
 where assessment_month = #{assessmentMonth, jdbcType = VARCHAR}
and assessment_type = #{assessmentType, jdbcType = VARCHAR} and enabled_flag = 1

mapper.delete:

update smqa
set enabled_flag = 0
from swm_monthly_quarterly_assessment smqa
where smqa.assessment_month = #{incomePeriod, jdbcType = VARCHAR}
and smqa.assessment_type = 'quarter' and smqa.enabled_flag = 1
and not exists (select 1 from swm_floating_wage sfw where sfw.enabled_flag = 1 and sfw.income_period = #{incomePeriod, jdbcType = VARCHAR}
and sfw.frozen_flag = 1
)

