update swm_monthly_quarterly_assessment set submission_identification_flag = 1, assessment_num = sqa.assessment_num, submitter = sqa.submitter, submit_time = sqa.submit_time from swm_monthly_quarterly_assessment smqa join swm_quarterly_assessment sqa on smqa.work_card = sqa.work_card and smqa.se_id = sqa.se_id where sqa.assessment_quarter = #{quarter, jdbcType = VARCHAR} and smqa.assessment_type = 'quarter' and smqa.enabled_flag = 1 and sqa.enabled_flag = 1 and smqa.assessment_month in (
#{item}
)


update  swm_monthly_quarterly_assessment  set frozen_flag = 1
  where frozen_flag = 0 and enabled_flag = 1 and assessment_type = 'month'
        and convert(bigint, left(assessment_month,4) + right(assessment_month,2))  <= #{updateLimit,jdbcType=BIGINT}


update  swm_monthly_quarterly_assessment  set frozen_flag = #{frozenFlag,jdbcType=BIT}
  where enabled_flag = 1 and assessment_type = 'month'
        and assessment_month = #{assessmentMonth,jdbcType=VARCHAR} and work_card = #{workCard,jdbcType=VARCHAR}
